const matches = $input.all();
const results = [];
for (const match of matches) {
  const data = match.json;
  results.push({
    json: {
      category: data.category || 'men',
      round: parseInt(data.round) || 1,
      round_name: data.round_name || 'Finals',
      index: parseInt(data.index) || 0,
      court: data.court || 'Unknown',
      competition_source: data.competition_source || 'FIP',
      month: new Date(data.played_at || Date.now()).getMonth() + 1,
      winner_enc: data.winner === 'team_1' ? 1 : 0,
      match_id: String(data.match_id || data.id || 'N/A'),
      match_name: data.name || 'Unknown',
      actual_duration: data.duration_minutes !== 'Unknown' ? data.duration_minutes : null
    }
  });
}
return results;

const items = $input.all();
const results = [];
for (const item of items) {
  const d = item.json;
  const predicted = parseFloat(d.predicted_duration || 90);
  let category = '';
  if (predicted < 70) category = '⚡ Short Match (<70 min)';
  else if (predicted < 100) category = '🎾 Standard Match (70-100 min)';
  else if (predicted < 130) category = '⏳ Long Match (100-130 min)';
  else category = '🔥 Marathon Match (>130 min)';
  results.push({
    json: {
      match_id: d.match_id || 'N/A',
      match_name: d.match_name || 'Unknown',
      predicted_duration_min: predicted.toFixed(1),
      duration_category: category,
      model: 'Random Forest Regressor (MAE=26.3 min)',
      warning: predicted > 150 ? '🚨 Unusually long match predicted!' : null,
      timestamp: new Date().toISOString()
    }
  });
}
return results;

const items = $input.all();
const alert = {
  type: 'LONG_MATCH_ALERT',
  pipeline: 'Regression — Match Duration',
  timestamp: new Date().toISOString(),
  matches: items.map(i => ({
    match_id: i.json.match_id,
    match_name: i.json.match_name,
    predicted_duration: i.json.predicted_duration_min + ' min'
  }))
};
await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://127.0.0.1:5000/log_error',
  headers: { 'Content-Type': 'application/json' },
  body: alert,
  json: true
});
return [{ json: alert }];

const items = $input.all();
const predictions = items.map(item => ({
  match_id: item.json.match_id || 'N/A',
  predicted_winner: item.json.duration_category || 'Unknown',
  probability_team1: item.json.predicted_duration_min || 0,
  probability_team2: 0,
  timestamp: item.json.timestamp || new Date().toISOString()
}));
const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://127.0.0.1:5000/save_predictions',
  headers: { 'Content-Type': 'application/json' },
  body: { predictions },
  json: true
});
return [{ json: response }];
